export const harnessAvailabilitySchema = z.object({
  harness: z.enum(["claude-code", "codex", "copilot", "none"]),
  available: z.boolean(),
  version: z.string().min(1).optional(),
  authStatus: z.enum(["authenticated", "unknown", "missing"]).optional(),
  notes: z.array(z.string()),
});

export const providerMatrixSchema = z.object({
  primary: harnessAvailabilitySchema,
  secondary: z.array(harnessAvailabilitySchema),
});

export const verificationGatesSchema = z.object({
  storyGate: z.string().min(1),
  epicGate: z.string().min(1),
  storyGateSource: z.string().min(1),
  epicGateSource: z.string().min(1),
});

export const preflightResultSchema = z.object({
  status: inspectOutcomeSchema,
  validatedConfig: implRunConfigSchema,
  providerMatrix: providerMatrixSchema,
  verificationGates: verificationGatesSchema.optional(),
  configValidationNotes: z.array(z.string()),
  promptAssets: z.object({
    basePromptsReady: z.boolean(),
    snippetsReady: z.boolean(),
    notes: z.array(z.string()),
  }),
  blockers: z.array(z.string()),
  notes: z.array(z.string()),
});

export type CliError = z.infer<typeof cliErrorSchema>;
export type CliArtifactRef = z.infer<typeof cliArtifactRefSchema>;
export type CliStatus = z.infer<typeof cliStatusSchema>;
export type InspectOutcome = z.infer<typeof inspectOutcomeSchema>;
export type InspectResult = z.infer<typeof inspectResultSchema>;
export type HarnessAvailability = z.infer<typeof harnessAvailabilitySchema>;
export type ProviderMatrix = z.infer<typeof providerMatrixSchema>;
export type VerificationGates = z.infer<typeof verificationGatesSchema>;
export type PreflightResult = z.infer<typeof preflightResultSchema>;

function statusForOutcome(outcome: string): CliStatus {
  switch (outcome) {
    case "ready":
      return "ok";
    case "needs-user-decision":
      return "needs-user-decision";
    case "blocked":
      return "blocked";
    default:
      return "error";
  }
}

export function exitCodeForStatus(status: CliStatus): number {
  switch (status) {
    case "ok":
      return 0;
    case "needs-user-decision":
      return 2;
    case "blocked":
      return 3;
    case "error":
    default:
      return 1;
  }
}

export function cliResultEnvelopeSchema<T extends z.ZodTypeAny>(resultSchema: T) {
  return z
    .object({
      command: z.string().min(1),
      version: z.literal(1),
      status: cliStatusSchema,
      outcome: z.string().min(1),
      result: resultSchema.optional(),
      errors: z.array(cliErrorSchema),
      warnings: z.array(z.string()),
      artifacts: z.array(cliArtifactRefSchema),
      startedAt: z.string().min(1),
      finishedAt: z.string().min(1),
    })
    .superRefine((value, ctx) => {
      const expectedStatus = statusForOutcome(value.outcome);
      if (expectedStatus !== value.status) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: `Envelope status '${value.status}' does not match outcome '${value.outcome}'`,
          path: ["status"],
        });
      }
    });
}

export function createResultEnvelope<T>(input: {
  command: string;
  outcome: string;
  result?: T;
  errors?: CliError[];
  warnings?: string[];
  artifacts?: CliArtifactRef[];
  startedAt: string;
  finishedAt: string;
}) {
  return {
    command: input.command,
    version: 1 as const,
    status: statusForOutcome(input.outcome),
    outcome: input.outcome,
    result: input.result,
    errors: input.errors ?? [],
    warnings: input.warnings ?? [],
    artifacts: input.artifacts ?? [],
    startedAt: input.startedAt,
    finishedAt: input.finishedAt,
  };
}

import { randomUUID } from "node:crypto";
import { mkdir, rm } from "node:fs/promises";
import { dirname, join, resolve } from "node:path";

export const ROOT = resolve(import.meta.dir, "../../..");

interface CreateSpecPackOptions {
  companionMode?: "two-file" | "four-file";
  includeStoriesDir?: boolean;
  includeStoriesFile?: boolean;
  includeEpic?: boolean;
  includeTechDesign?: boolean;
  includeTestPlan?: boolean;
  includeImplInsert?: boolean;
  includeVerifierInsert?: boolean;
}

export async function createTempDir(scope: string): Promise<string> {
  const dir = join(ROOT, ".test-tmp", "impl-cli", scope, randomUUID());
  await rm(dir, { recursive: true, force: true });
  await mkdir(dir, { recursive: true });
  return dir;
}

export async function writeTextFile(path: string, content: string): Promise<void> {
  await mkdir(dirname(path), { recursive: true });
  await Bun.write(path, content);
}

export async function createSpecPack(
  scope: string,
  options: CreateSpecPackOptions = {}
): Promise<string> {
  const specPackRoot = await createTempDir(scope);
  const {
    companionMode = "two-file",
    includeStoriesDir = true,
    includeStoriesFile = false,
    includeEpic = true,
    includeTechDesign = true,
    includeTestPlan = true,
    includeImplInsert = false,
    includeVerifierInsert = false,
  } = options;

  if (includeEpic) {
    await writeTextFile(join(specPackRoot, "epic.md"), "# Epic\n");
  }

  if (includeTechDesign) {
    await writeTextFile(join(specPackRoot, "tech-design.md"), "# Technical Design\n");
  }

  if (includeTestPlan) {
    await writeTextFile(join(specPackRoot, "test-plan.md"), "# Test Plan\n");
  }

  if (companionMode === "four-file") {
    await writeTextFile(
      join(specPackRoot, "tech-design-cli-runtime.md"),
      "# CLI Runtime Companion\n"
    );
    await writeTextFile(
      join(specPackRoot, "tech-design-skill-process.md"),
      "# Skill Process Companion\n"
    );
  }

  if (includeStoriesDir) {
    await writeTextFile(
      join(specPackRoot, "stories", "00-foundation.md"),
      "# Story 0: Foundation\n"
    );
    await writeTextFile(
      join(specPackRoot, "stories", "01-next.md"),
      "# Story 1: Next\n"
    );
  }

  if (includeStoriesFile) {
    await writeTextFile(join(specPackRoot, "stories.md"), "# Stories\n");
  }

  if (includeImplInsert) {
    await writeTextFile(
      join(specPackRoot, "custom-story-impl-prompt-insert.md"),
      "Custom implementor insert\n"
    );
  }

  if (includeVerifierInsert) {
    await writeTextFile(
      join(specPackRoot, "custom-story-verifier-prompt-insert.md"),
      "Custom verifier insert\n"
    );
  }

  return specPackRoot;
}

export interface CliRunResult {
  exitCode: number;
  stdout: string;
  stderr: string;
}

export async function runSourceCli(
  args: string[],
  options: {
    env?: Record<string, string | undefined>;
  } = {}
): Promise<CliRunResult> {
  const proc = Bun.spawn(["bun", "run", "processes/impl-cli/cli.ts", ...args], {
    cwd: ROOT,
    stdout: "pipe",
    stderr: "pipe",
    env: {
      ...process.env,
      ...options.env,
      FORCE_COLOR: "0",
    },
  });

  const stdout = await new Response(proc.stdout).text();
  const stderr = await new Response(proc.stderr).text();
  const exitCode = await proc.exited;

  return {
    exitCode,
    stdout,
    stderr,
  };
}

export function parseJsonOutput<T>(stdout: string): T {
  return JSON.parse(stdout.trim()) as T;
}

import { execFile } from "node:child_process";
import { promisify } from "node:util";

import type { ImplRunConfig, SecondaryHarness } from "./config-schema";
import { resolveGitRepoRoot } from "./git-repo";
import type { HarnessAvailability, ProviderMatrix } from "./result-contracts";

const execFileAsync = promisify(execFile);
const DEFAULT_PROVIDER_CHECK_TIMEOUT_MS = 1_000;

function redactSensitiveText(text: string): string {
  return text
    .replace(/\bBearer\s+[A-Za-z0-9._-]+\b/gi, "Bearer [REDACTED]")
    .replace(/\b(token|auth|authorization|api[_-]?key)\s*[:=]\s*\S+/gi, "$1=[REDACTED]");
}

async function runCommand(params: {
  file: string;
  args: string[];
  cwd: string;
  env?: Record<string, string | undefined>;
  timeoutMs: number;
}) {
  try {
    const result = await execFileAsync(params.file, params.args, {
      cwd: params.cwd,
      env: {
        ...process.env,
        ...params.env,
      },
      timeout: params.timeoutMs,
    });
    return {
      success: true as const,
      stdout: redactSensitiveText(result.stdout.trim()),
      stderr: redactSensitiveText(result.stderr.trim()),
    };
  } catch (error) {
    const failed = error as {
      stdout?: string;
      stderr?: string;
      code?: string | number;
      message?: string;
      killed?: boolean;
      signal?: string;
    };
    return {
      success: false as const,
      stdout: redactSensitiveText(failed.stdout?.trim() ?? ""),
      stderr: redactSensitiveText(
        failed.stderr?.trim() ?? failed.message ?? String(error)
      ),
      code: failed.code,
      timedOut: failed.signal === "SIGTERM" || failed.killed === true,
    };
  }
}

function executableForHarness(harness: "claude-code" | SecondaryHarness): string | null {
  switch (harness) {
    case "claude-code":
      return "claude";
    case "codex":
      return "codex";
    case "copilot":
      return "copilot";
    case "none":
      return null;
  }
}

function failureNotes(result: {
  stderr: string;
  timedOut?: boolean;
  code?: string | number;
}, executable: string, step: string): string[] {
  if (result.stderr) {
    return [result.stderr];
  }

  if (result.timedOut) {
    return [`${executable} ${step} timed out`];
  }

  return [`Unable to execute ${executable} ${step}`];
}

async function checkHarnessAvailability(input: {
  harness: "claude-code" | SecondaryHarness;
  cwd: string;
  env?: Record<string, string | undefined>;
  timeoutMs: number;
}): Promise<HarnessAvailability> {
  const executable = executableForHarness(input.harness);
  if (!executable) {
    return {
      harness: "none",
      available: true,
      authStatus: "unknown",
      notes: [],
    };
  }

  const version = await runCommand({
    file: executable,
    args: ["--version"],
    cwd: input.cwd,
    env: input.env,
    timeoutMs: input.timeoutMs,
  });
  if (!version.success) {
    return {
      harness: input.harness,
      available: false,
      authStatus: version.code === "ENOENT" ? "missing" : "unknown",
      notes: failureNotes(version, executable, "--version"),
    };
  }

  const auth = await runCommand({
    file: executable,
    args: ["auth", "status"],
    cwd: input.cwd,
    env: input.env,
    timeoutMs: input.timeoutMs,
  });
  if (!auth.success) {
    const authStatus =
      auth.timedOut || auth.code === "ETIMEDOUT"
        ? "unknown"
        : auth.code === 1 || auth.stderr.toLowerCase().includes("missing")
          ? "missing"
          : "unknown";

    return {
      harness: input.harness,
      available: false,
      version: version.stdout,
      authStatus,
      notes: failureNotes(auth, executable, "auth status"),
    };
  }

  return {
    harness: input.harness,
    available: true,
    version: version.stdout,
    authStatus: "authenticated",
    notes: auth.stdout ? [auth.stdout] : [],
  };
}

function requestedSecondaryHarnesses(config: ImplRunConfig): SecondaryHarness[] {
  const harnesses = new Set<SecondaryHarness>();
  for (const assignment of [
    config.story_implementor,
    config.quick_fixer,
    config.story_verifier_1,
    config.story_verifier_2,
    ...config.epic_verifiers,
    config.epic_synthesizer,
  ]) {
    if (assignment.secondary_harness !== "none") {
      harnesses.add(assignment.secondary_harness);
    }
  }
  return [...harnesses];
}

export async function resolveProviderMatrix(input: {
  specPackRoot: string;
  config: ImplRunConfig;
  env?: Record<string, string | undefined>;
  timeoutMs?: number;
}): Promise<ProviderMatrix> {
  const cwd = (await resolveGitRepoRoot(input.specPackRoot)) ?? input.specPackRoot;
  const timeoutMs = input.timeoutMs ?? DEFAULT_PROVIDER_CHECK_TIMEOUT_MS;
  const primary = await checkHarnessAvailability({
    harness: "claude-code",
    cwd,
    env: input.env,
    timeoutMs,
  });
  const secondary: HarnessAvailability[] = [];

  for (const harness of requestedSecondaryHarnesses(input.config)) {
    secondary.push(
      await checkHarnessAvailability({
        harness,
        cwd,
        env: input.env,
        timeoutMs,
      })
    );
  }

  return {
    primary,
    secondary,
  };
}

  const assets = getEmbeddedPromptAssets();
  const basePromptId = basePromptIdForRole(input.role);
  const snippetIds = snippetIdsForInput(input);
  const values = runtimeValues(input);
  const publicInsert =
    input.role === "story_implementor"
      ? await loadPublicInsert(input.implementationPromptInsertPath)
      : input.role === "story_verifier"
        ? await loadPublicInsert(input.verifierPromptInsertPath)
        : {};

  const sections = [
    interpolateTemplate(assets.base[basePromptId], values),
    ...snippetIds.map((snippetId) =>
      interpolateTemplate(assets.snippets[snippetId], values)
    ),
    selfReviewSection(input),
    publicInsert.content ? publicInsert.content.trimEnd() : "",
  ].filter((section) => section.length > 0);

  return {
    prompt: `${sections.join("\n\n")}\n`,
    basePromptId,
    snippetIds,
    publicInsertIds: publicInsert.assetId ? [publicInsert.assetId] : [],
  };
}

import { relative, resolve } from "node:path";

import { loadConfig } from "c12";
import { z } from "zod";

export const RUN_CONFIG_FILE_NAME = "impl-run.config.json";

export const reasoningEffortSchema = z.enum(["low", "medium", "high", "xhigh"]);
export const primaryHarnessSchema = z.literal("claude-code");
export const secondaryHarnessSchema = z.enum(["codex", "copilot", "none"]);

export const roleAssignmentSchema = z.object({
  secondary_harness: secondaryHarnessSchema,
  model: z.string().min(1),
  reasoning_effort: reasoningEffortSchema,
});

export const epicVerifierAssignmentSchema = roleAssignmentSchema.extend({
  label: z.string().min(1),
});

export const implRunConfigSchema = z
  .object({
    version: z.literal(1),
    primary_harness: primaryHarnessSchema,
    story_implementor: roleAssignmentSchema,
    quick_fixer: roleAssignmentSchema,
    story_verifier_1: roleAssignmentSchema,
    story_verifier_2: roleAssignmentSchema,
    self_review: z.object({
      passes: z.number().int().min(1).max(5),
    }),
    epic_verifiers: z.array(epicVerifierAssignmentSchema).min(1),
    epic_synthesizer: roleAssignmentSchema,
  })
  .superRefine((value, ctx) => {
    if (value.story_implementor.secondary_harness === "copilot") {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message:
          "story_implementor.secondary_harness cannot be copilot in v1",
        path: ["story_implementor", "secondary_harness"],
      });
    }

    const seenLabels = new Set<string>();
    for (const [index, verifier] of value.epic_verifiers.entries()) {
      if (seenLabels.has(verifier.label)) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: "Duplicate epic verifier label",
          path: ["epic_verifiers", index, "label"],
        });
      }
      seenLabels.add(verifier.label);
    }
  });

export type ReasoningEffort = z.infer<typeof reasoningEffortSchema>;
export type PrimaryHarness = z.infer<typeof primaryHarnessSchema>;
export type SecondaryHarness = z.infer<typeof secondaryHarnessSchema>;
export type RoleAssignment = z.infer<typeof roleAssignmentSchema>;
export type EpicVerifierAssignment = z.infer<typeof epicVerifierAssignmentSchema>;
export type ImplRunConfig = z.infer<typeof implRunConfigSchema>;

export function resolveRunConfigPath(
  specPackRoot: string,
  configPath?: string
): string {
  if (!configPath) {
    return resolve(specPackRoot, RUN_CONFIG_FILE_NAME);
  }

  return resolve(specPackRoot, configPath);
}

export async function loadRunConfig(input: {
  specPackRoot: string;
  configPath?: string;
}): Promise<ImplRunConfig> {
  const resolvedPath = resolveRunConfigPath(input.specPackRoot, input.configPath);
  const { config } = await loadConfig({
    cwd: resolve(input.specPackRoot),
    configFile: relative(resolve(input.specPackRoot), resolvedPath),
    configFileRequired: true,
    rcFile: false,
    globalRc: false,
    packageJson: false,
    dotenv: false,
    extend: false,
  });

  return implRunConfigSchema.parse(config);
}

import { mkdir, readdir } from "node:fs/promises";
import { join, resolve } from "node:path";

import { writeTextFile } from "./fs-utils";

export async function nextArtifactPath(
  specPackRoot: string,
  command: string
): Promise<string> {
  const artifactDir = join(resolve(specPackRoot), "artifacts", command);
  await mkdir(artifactDir, { recursive: true });

  const entries = await readdir(artifactDir, { withFileTypes: true });
  const existingCount = entries.filter(
    (entry) => entry.isFile() && entry.name.endsWith(".json")
  ).length;
  const nextIndex = String(existingCount + 1).padStart(3, "0");

  return join(artifactDir, `${nextIndex}-${command}.json`);
}

export async function writeJsonArtifact(
  path: string,
  payload: unknown
): Promise<void> {
  await writeTextFile(path, `${JSON.stringify(payload)}\n`);
}

import { defineCommand } from "citty";
import { ZodError } from "zod";

import { nextArtifactPath, writeJsonArtifact } from "../core/artifact-writer";
import { loadRunConfig } from "../core/config-schema";
import { resolveVerificationGates } from "../core/gate-discovery";
import { inspectPromptAssets } from "../core/prompt-assets";
import { resolveProviderMatrix } from "../core/provider-checks";
import {
  cliResultEnvelopeSchema,
  createResultEnvelope,
  exitCodeForStatus,
  preflightResultSchema,
  type CliArtifactRef,
  type CliError,
  type CliStatus,
  type PreflightResult,
} from "../core/result-contracts";
import { inspectSpecPack } from "../core/spec-pack";

interface OutputEnvelope {
  command: string;
  version: 1;
  status: CliStatus;
  outcome: string;
  result?: unknown;
  errors: CliError[];
  warnings: string[];
  artifacts: CliArtifactRef[];
  startedAt: string;
  finishedAt: string;
}

function renderHumanSummary(envelope: OutputEnvelope) {
  if (
    typeof envelope.result !== "object" ||
    envelope.result === null ||
    !("providerMatrix" in envelope.result)
  ) {
    return `preflight: ${envelope.outcome}`;
  }

  const result = envelope.result as PreflightResult;
  const lines = [
    `preflight: ${envelope.outcome}`,
    `primary: ${result.providerMatrix.primary.available ? "ready" : "blocked"}`,
    `secondary: ${result.providerMatrix.secondary.length}`,
  ];

  if (result.verificationGates) {
    lines.push(`story gate: ${result.verificationGates.storyGate}`);
    lines.push(`epic gate: ${result.verificationGates.epicGate}`);
  }

  return lines.join("\n");
}

function emitOutput(params: {
  envelope: OutputEnvelope;
  json: boolean;
}) {
  if (params.json) {
    console.log(JSON.stringify(params.envelope));
    return;
  }

  console.log(renderHumanSummary(params.envelope));
}

function unavailableProviderErrors(
  providerMatrix: PreflightResult["providerMatrix"]
): CliError[] {
  const errors: CliError[] = [];

  if (!providerMatrix.primary.available) {
    errors.push({
      code: "PROVIDER_UNAVAILABLE",
      message: "Primary harness is unavailable",
      detail: providerMatrix.primary.notes.join("; "),
    });
  }

  for (const provider of providerMatrix.secondary) {
    if (!provider.available) {
      errors.push({
        code: "PROVIDER_UNAVAILABLE",
        message: `Requested secondary harness is unavailable: ${provider.harness}`,
        detail: provider.notes.join("; "),
      });
    }
  }

  return errors;
}

export default defineCommand({
  meta: {
    name: "preflight",
    description:
      "Validate run config, verification gates, and provider availability.",
  },
  args: {
    "spec-pack-root": {
      type: "string",
      description: "Absolute or relative path to the spec-pack root",
      required: true,
    },
    config: {
      type: "string",
      description: "Explicit run-config file relative to the spec-pack root",
    },
    "story-gate": {
      type: "string",
      description: "Explicit story verification gate command",
    },
    "epic-gate": {
      type: "string",
      description: "Explicit epic verification gate command",
    },
    json: {
      type: "boolean",
      description: "Emit the structured JSON envelope on stdout",
    },
  },
  async run({ args }) {
    const startedAt = new Date().toISOString();

    try {
      const inspectResult = await inspectSpecPack(args["spec-pack-root"]);
      const artifactPath = await nextArtifactPath(
        inspectResult.specPackRoot,
        "preflight"
      );

      if (inspectResult.status !== "ready") {
        const envelope: OutputEnvelope = createResultEnvelope({
          command: "preflight",
          outcome: inspectResult.status,
          errors: [
            {
              code: "INVALID_SPEC_PACK",
              message:
                inspectResult.status === "blocked"
                  ? "Spec-pack inspection failed"
                  : "Spec-pack inspection requires a user decision",
              detail:
                inspectResult.blockers.join("; ") || inspectResult.notes.join("; "),
            },
          ],
          artifacts: [
            {
              kind: "result-envelope",
              path: artifactPath,
            },
          ],
          startedAt,
          finishedAt: new Date().toISOString(),
        });

        await writeJsonArtifact(artifactPath, envelope);
        emitOutput({
          envelope,
          json: Boolean(args.json),
        });
        process.exitCode = exitCodeForStatus(envelope.status);
        return;
      }

      const validatedConfig = await loadRunConfig({
        specPackRoot: inspectResult.specPackRoot,
        configPath: args.config,
      });
      const providerMatrix = await resolveProviderMatrix({
        specPackRoot: inspectResult.specPackRoot,
        config: validatedConfig,
        env: process.env,
      });
      const gateResolution = await resolveVerificationGates({
        specPackRoot: inspectResult.specPackRoot,
        explicitStoryGate: args["story-gate"],
        explicitEpicGate: args["epic-gate"],
      });
      const promptAssets = inspectPromptAssets();
      const notes = [...inspectResult.notes];

      if (
        [
          validatedConfig.story_implementor,
          validatedConfig.quick_fixer,
          validatedConfig.story_verifier_1,
          validatedConfig.story_verifier_2,
          ...validatedConfig.epic_verifiers,
          validatedConfig.epic_synthesizer,
        ].every((assignment) => assignment.secondary_harness === "none")
      ) {
        notes.push(
          "GPT-capable secondary harnesses are unavailable for this run; the orchestrator should record the Claude-only degraded mode."
        );
      }

      const providerErrors = unavailableProviderErrors(providerMatrix);
      const blockers: string[] = [];
      const errors: CliError[] = [];
      let outcome: "ready" | "needs-user-decision" | "blocked" = "ready";

      if (providerErrors.length > 0) {
        outcome = "blocked";
        errors.push(...providerErrors);
        blockers.push(...providerErrors.map((error) => error.message));
      } else if (!promptAssets.basePromptsReady || !promptAssets.snippetsReady) {
        outcome = "blocked";
        errors.push({
          code: "PROMPT_ASSET_MISSING",
          message: "Embedded prompt assets are incomplete",
          detail: promptAssets.notes.join("; "),
        });
        blockers.push("Embedded prompt assets are incomplete");
      } else if (gateResolution.status === "needs-user-decision") {
        outcome = "needs-user-decision";
        errors.push(...gateResolution.errors);
        notes.push(...gateResolution.notes);
      }

      const preflightResult: PreflightResult = {
        status: outcome,
        validatedConfig,
        providerMatrix,
        verificationGates: gateResolution.verificationGates,
        configValidationNotes: [],
        promptAssets,
        blockers,
        notes,
      };
      const envelope = cliResultEnvelopeSchema(preflightResultSchema).parse(
        createResultEnvelope({
          command: "preflight",
          outcome,
          result: preflightResult,
          errors,
          artifacts: [
            {
              kind: "result-envelope",
              path: artifactPath,
            },
          ],
          startedAt,
          finishedAt: new Date().toISOString(),
        })
      );

      await writeJsonArtifact(artifactPath, envelope);
      emitOutput({
        envelope,
